int outDegree[MAXN]; // 每个节点的出度
double dp[MAXN]; // dp[u] 表示从 u 到终点的期望路径长度

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    // 输入
    cin >> N >> M;
    for (int i = 0; i < M; ++i) {
        int a, b, c;
        cin >> a >> b >> c;
        adj[a].emplace_back(b, c);
        outDegree[a]++;
    }

    // 拓扑排序 + 动态规划
    queue<int> q;
    for (int i = 1; i <= N; ++i) {
        if (outDegree[i] == 0) {
            q.push(i);
        }
    }

    while (!q.empty()) {
        int u = q.front();
        q.pop();
        for (auto [v, c] : adj[u]) {
            dp[u] += (c + dp[v]) / outDegree[u];
        }
        for (auto [v, c] : adj[u]) {
            if (--outDegree[v] == 0) {
                q.push(v);
            }
        }
    }

    // 输出结果，保留两位小数
    cout << fixed << setprecision(2) << dp[1] << endl;

    return 0;
}

