#include <bits/stdc++.h>
using namespace std;
using ll = long long;
const int INF = 0x3f3f3f3f;
const int MAXN = 100010;  // 最大节点数
const int MAXM = 200010;  // 最大边数

int N, M;
vector<pair<int, int>> G[MAXN];  // 邻接表，存储 (目标节点, 边长度)
int outDegree[MAXN];             // 每个节点的出度
int inDegree[MAXN];              // 每个节点的入度 [FIX] 添加入度数组用于拓扑排序
double E[MAXN];                  // 期望路径长度

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    // 输入
    cin >> N >> M;
    for (int i = 0; i < M; i++) {
        int a, b, c;
        cin >> a >> b >> c;
        G[a].emplace_back(b, c);
        outDegree[a]++;
        inDegree[b]++;  // [FIX] 统计入度
    }

    // 初始化期望值 [FIX] 显式初始化所有节点的期望值
    fill(E, E + MAXN, 0.0);

    // 拓扑排序 [FIX] 使用标准拓扑排序算法
    queue<int> q;
    for (int i = 1; i <= N; i++) {
        if (inDegree[i] == 0) {
            q.push(i);
        }
    }

    // 动态规划计算期望值 [FIX] 按拓扑序正确计算期望值
    while (!q.empty()) {
        int u = q.front();
        q.pop();

        if (outDegree[u] > 0) {  // 处理非终点节点
            for (auto [v, c] : G[u]) {
                E[u] += (c + E[v]) / outDegree[u];
            }
        }

        // 更新邻接节点的入度
        for (auto [v, c] : G[u]) {
            inDegree[v]--;
            if (inDegree[v] == 0) {
                q.push(v);
            }
        }
    }

    // 输出结果，保留两位小数
    cout << fixed << setprecision(2) << E[1] << endl;

